from collections import defaultdict

# Retrieve input variables from the scenario
sales_data = input.get('salesData', [])

# Aggregate by month
monthly_stats = defaultdict(lambda: {
    'total_leads': 0,
    'closed_won': 0,
    'total_revenue': 0,
    'missing_fields': set()
})

# Variable to hold the global yearly total
yearly_closed_deals = 0

for record in sales_data:
    month = record.get('Month')

    # If no month, we can't assign this record anywhere — skip entirely
    if not month:
        continue

    # --- Validate and extract Status ---
    status = record.get('Status')
    if status is None or str(status).strip() == '':
        monthly_stats[month]['missing_fields'].add('Status')
        status = ''
    else:
        status = str(status).strip()

    # --- Validate and extract Deal_Amount ---
    raw_amount = record.get('Deal_Amount')
    if raw_amount is None or str(raw_amount).strip() == '':
        monthly_stats[month]['missing_fields'].add('Deal_Amount')
        deal_amount = 0.0
    else:
        try:
            deal_amount = float(str(raw_amount).replace('$', '').replace(',', '').strip())
        except (ValueError, TypeError):
            monthly_stats[month]['missing_fields'].add('Deal_Amount')
            deal_amount = 0.0

    # --- Count every record as a lead ---
    monthly_stats[month]['total_leads'] += 1

    # --- Only count closed won if status is clean ---
    if status == 'Closed Won':
        monthly_stats[month]['closed_won'] += 1
        monthly_stats[month]['total_revenue'] += deal_amount
        yearly_closed_deals += 1

# Build the final output arrays
monthly_revenue_trend = []
monthly_conversion_rate = []

for month in sorted(monthly_stats.keys()):
    stats = monthly_stats[month]
    missing = stats['missing_fields']

    # --- Monthly Revenue Trend ---
    # Requires Deal_Amount and Status to be clean
    if 'Deal_Amount' in missing or 'Status' in missing:
        monthly_revenue_trend.append({
            'Month': month,
            'Total_Revenue': 'Insufficient Data',
            'Missing_Fields': list(missing)
        })
    else:
        monthly_revenue_trend.append({
            'Month': month,
            'Total_Revenue': stats['total_revenue'],
            'Missing_Fields': []
        })

    # --- Monthly Conversion Rate ---
    # Requires Status to be clean to correctly identify won vs lost vs new
    if 'Status' in missing:
        monthly_conversion_rate.append({
            'Month': month,
            'Conversion_Rate_%': 'Insufficient Data',
            'Missing_Fields': list(missing)
        })
    else:
        conversion_rate = 0
        if stats['total_leads'] > 0:
            conversion_rate = round((stats['closed_won'] / stats['total_leads']) * 100, 2)

        monthly_conversion_rate.append({
            'Month': month,
            'Conversion_Rate_%': conversion_rate,
            'Missing_Fields': []
        })

# Return values back to Make.com
return {
    'yearly_closed_deals': yearly_closed_deals,
    'monthly_revenue_trend': monthly_revenue_trend,
    'monthly_conversion_rate': monthly_conversion_rate,
    'sales_data_raw': sales_data
}

from collections import defaultdict

# Retrieve input variables from Make.com
project_data = input.get('projectData', [])

DATE_FORMAT = "%Y-%m-%d"

def parse_date(value):
    """Returns a clean date string (YYYY-MM-DD) or None if missing or wrong format."""
    if not value or str(value).strip() == '':
        return None
    cleaned = str(value).strip()
    # Validate it is a real date by checking structure and parsing
    try:
        from datetime import datetime
        datetime.strptime(cleaned, DATE_FORMAT)
        return cleaned
    except ValueError:
        return None

def parse_cost(value):
    """
    Strips £ or $ and commas, returns float or None if missing or unparseable.
    Your data uses £ — e.g. £1200.00
    """
    if value is None or str(value).strip() == '':
        return None
    try:
        cleaned = str(value).strip().replace('£', '').replace('$', '').replace(',', '')
        return float(cleaned)
    except (ValueError, TypeError):
        return None

# Aggregate by month
# missing_date  → flags On_Time_Rate_%  as Insufficient Data
# missing_cost  → flags Cost_Variance_% as Insufficient Data
monthly_stats = defaultdict(lambda: {
    'total_tasks':        0,
    'on_time_tasks':      0,
    'total_actual_cost':  0.0,
    'total_budgeted_cost':0.0,
    'missing_date':       False,
    'missing_cost':       False
})

for record in project_data:
    month = record.get('Month')

    if not month or str(month).strip() == '':
        continue

    month = str(month).strip()

    # --- Planned_End_Date ---
    planned_date = parse_date(record.get('Planned_End_Date'))
    if 'Planned_End_Date' not in record or planned_date is None:
        monthly_stats[month]['missing_date'] = True

    # --- Actual_End_Date ---
    actual_date = parse_date(record.get('Actual_End_Date'))
    if 'Actual_End_Date' not in record or actual_date is None:
        monthly_stats[month]['missing_date'] = True

    # --- Budgeted_Cost ---
    budgeted_cost = parse_cost(record.get('Budgeted_Cost'))
    if 'Budgeted_Cost' not in record or budgeted_cost is None:
        monthly_stats[month]['missing_cost'] = True
        budgeted_cost = 0.0

    # --- Actual_Cost ---
    actual_cost = parse_cost(record.get('Actual_Cost'))
    if 'Actual_Cost' not in record or actual_cost is None:
        monthly_stats[month]['missing_cost'] = True
        actual_cost = 0.0

    # Count every record as a task
    monthly_stats[month]['total_tasks'] += 1

    # On-time: Actual_End_Date <= Planned_End_Date
    # YYYY-MM-DD strings compare correctly as plain text — no datetime conversion needed
    if actual_date and planned_date:
        if actual_date <= planned_date:
            monthly_stats[month]['on_time_tasks'] += 1

    # Accumulate costs
    monthly_stats[month]['total_actual_cost']   += actual_cost
    monthly_stats[month]['total_budgeted_cost'] += budgeted_cost


# Build output arrays
monthly_on_time_rate  = []
monthly_cost_variance = []

for month in sorted(monthly_stats.keys()):
    stats = monthly_stats[month]

    # --- On-Time Completion Rate ---
    # Insufficient Data if ANY task in this month is missing either date field
    if stats['missing_date']:
        monthly_on_time_rate.append({
            'Month':          month,
            'On_Time_Rate_%': 'Insufficient Data'
        })
    else:
        on_time_rate = 0
        if stats['total_tasks'] > 0:
            on_time_rate = round(
                (stats['on_time_tasks'] / stats['total_tasks']) * 100, 2
            )
        monthly_on_time_rate.append({
            'Month':          month,
            'On_Time_Rate_%': on_time_rate
        })

    # --- Cost Variance ---
    # Insufficient Data if ANY task in this month is missing either cost field
    if stats['missing_cost']:
        monthly_cost_variance.append({
            'Month':           month,
            'Cost_Variance_%': 'Insufficient Data'
        })
    else:
        cost_variance = 0
        if stats['total_budgeted_cost'] > 0:
            cost_variance = round(
                ((stats['total_actual_cost'] - stats['total_budgeted_cost'])
                 / stats['total_budgeted_cost']) * 100, 2
            )
        monthly_cost_variance.append({
            'Month':           month,
            'Cost_Variance_%': cost_variance
        })

return {
    'monthly_on_time_rate':  monthly_on_time_rate,
    'monthly_cost_variance': monthly_cost_variance
}
